import React from "react";
import TestimonialCard from "./TestimonialCard";

const testimonials = [
  {
    id: 1,
    name: "Anonymous",
    rating: 5,
    text: `I am constantly running with 3 kids & on my feet solving problems left & right for 40+ hours a week at work. I try to drink a ton of water daily but it just didn’t seem to cut it. Enter this stuff...after 1 week of drinking a minimum of 2 packs daily...I feel great!`,
    img: "/media/aboutus/testimonial1.jpg",
  },
  {
    id: 2,
    name: "Kristi",
    rating: 5,
    text: `I started to replace my afternoon cup of coffee with the caffeinated Hydrant and I love it. You get a nice perk up without any jitters and feel great because you’re hydrating yourself instead of dehydrating!`,
    img: "/media/aboutus/testimonial2.jpg",
  },
  {
    id: 3,
    name: "Anonymous",
    rating: 5,
    text: `I hate water but since finding Hydrant I drink nothing else. And even when I try to drink a soda or juice, whatever, it doesn't taste good anymore which then gets me to drink more water!! I feel so much better, more energy, more focus, my skin looks more hydrated, and my overall health just feels brighter and more vibrant.`,
    img: "/media/aboutus/testimonial3.jpg",
  },
];

const PersonalSection = () => {
  return (
    <section style={{ maxWidth: "1200px", margin: "0 auto", marginBottom: "5rem", padding: "0 1rem" }}>
      <h2
        style={{
          fontWeight: "900",
          fontSize: "2.75rem",
          textAlign: "center",
          marginBottom: "2rem",
          color: "#003E73",
        }}
      >
        Loved by thousands
      </h2>
      <div style={{ display: "flex", justifyContent: "space-between", gap: "1rem", flexWrap: "wrap" }}>
        {testimonials.map((t) => (
          <TestimonialCard key={t.id} testimonial={t} />
        ))}
      </div>
    </section>
  );
};

export default PersonalSection;
